 1	import * as React from 'react';
 2	import { App } from '../../types/App';
 3	import { Alert, Card, CardBody, CardHeader, Title, TitleSizes, TooltipPosition } from '@patternfly/react-core';
 4	import { DetailDescription } from '../../components/DetailDescription/DetailDescription';
 5	import { isMultiCluster, serverConfig } from '../../config';
 6	import { Labels } from '../../components/Label/Labels';
 7	import { kialiStyle } from 'styles/StyleUtils';
 8	import * as H from '../../types/Health';
 9	import { HealthIndicator } from '../../components/Health/HealthIndicator';
10	import { PFBadge, PFBadges } from '../../components/Pf/PfBadges';
11	import { AmbientLabel, tooltipMsgType } from '../../components/Ambient/AmbientLabel';
12	import { getAppLabelName } from 'config/ServerConfig';
13	
14	type AppDescriptionProps = {
15	  app?: App;
16	  health?: H.Health;
17	  isSupported?: boolean;
18	};
19	
20	const iconStyle = kialiStyle({
21	  display: 'inline-block'
22	});
23	
24	const healthIconStyle = kialiStyle({
25	  marginLeft: '0.5rem',
26	  verticalAlign: '-0.075rem'
27	});
28	
29	export const AppDescription: React.FC<AppDescriptionProps> = (props: AppDescriptionProps) => {
30	  const appLabels: { [key: string]: string } = {};
31	
32	  if (props.app?.workloads && props.app.workloads.length > 0) {
33	    const appLabelName = getAppLabelName(props.app.workloads[0].labels);
34	    if (appLabelName) {
35	      appLabels[appLabelName] = props.app.name;
36	    }
37	  }
38	
39	  return props.app ? (
40	    <Card id="AppDescriptionCard" data-test="app-description-card">
41	      <CardHeader>
42	        <Title headingLevel="h5" size={TitleSizes.lg}>
43	          <div key="service-icon" className={iconStyle}>
44	            <PFBadge badge={PFBadges.App} position={TooltipPosition.top} />
45	          </div>
46	
47	          {props.app.name}
48	
49	          <span className={healthIconStyle}>
50	            <HealthIndicator id={props.app.name} health={props.health} />
51	          </span>
52	
53	          {props.app.isAmbient && <AmbientLabel tooltip={tooltipMsgType.app} />}
54	        </Title>
55	
56	        {props.app.cluster && isMultiCluster && (
57	          <div key="cluster-icon" style={{ paddingBottom: '0.5rem' }}>
58	            <PFBadge badge={PFBadges.Cluster} position={TooltipPosition.right} /> {props.app.cluster}
59	          </div>
60	        )}
61	        {!props.isSupported && (
62	          <Alert
63	            variant="info"
64	            isInline={true}
65	            title="Limited info is supplied due to the referenced workload type"
66	            style={{ marginTop: '0.25rem' }}
67	          />
68	        )}
69	      </CardHeader>
70	      <CardBody>
71	        <Labels
72	          labels={appLabels}
73	          tooltipMessage={`Workloads and Services grouped by ${serverConfig.istioLabels.appLabelName ?? 'app'} label`}
74	        />
75	
76	        <DetailDescription
77	          namespace={props.app ? props.app.namespace.name : ''}
78	          workloads={props.app ? props.app.workloads : []}
79	          services={props.app ? props.app.serviceNames : []}
80	          health={props.health}
81	          cluster={props.app?.cluster}
82	        />
83	      </CardBody>
84	    </Card>
85	  ) : (
86	    <>Loading</>
87	  );
88	};

